        const cleanLoc = rawLoc.replace(/[-Ff]/g, '').trim();

        // 記錄起來方便 Output 查看
        cleanLocationsLog.push(cleanLoc);

        // B. 建構 Regex Pattern (保留您原本的邏輯)
        // 1. 前面: 行首 或 非英數字
        // 2. 中間: cleanLoc
        // 3. 後面: F/f 或 非英數字 或 行尾
        const regexPattern = `(^|[^a-zA-Z0-9])${cleanLoc}(F|f|[^a-zA-Z0-9]|$)`;

        // C. 生成 SQL 片段
        // PostgreSQL 使用 ~* (不分大小寫)
        return `subject ~* '${regexPattern}'`;

        // 如果是 Oracle，請改用:
        // return `REGEXP_LIKE(subject, '${regexPattern}', 'i')`;
    });

    // 將所有 Regex 條件用 OR 串接，並加上括號保護
    subjectCondition = `AND (${subjectClauses.join(' OR ')})`;
}

