={{
  (() => {
    try {
      const offsetMean = $json.offset_mean.toString();

      let value1, value2;

      // 檢查是否包含範圍符號
      if (!offsetMean.includes('~')) {
        // 單一數值的情況
        const singleValue = parseFloat(offsetMean);
        if (isNaN(singleValue)) return null;

        // 設定範圍為 ±2
        value1 = singleValue - 2;
        value2 = singleValue + 2;
      } else {
        // 範圍值的情況
        const range = offsetMean.split('~');
        if (range.length !== 2) return null;

        value1 = parseFloat(range[0]);
        value2 = parseFloat(range[1]);

        if (isNaN(value1) || isNaN(value2)) return null;
      }

      const testValue = parseFloat($json.ppm_avg);
      if (isNaN(testValue)) return null;

      // 自動判斷最小值和最大值
      const min = Math.min(value1, value2);
      const max = Math.max(value1, value2);

      // 正常範圍內
      if (testValue >= min && testValue <= max) {
        return true;
      }

      // 警告區間: (min-1, min) 或 (max, max+1)
      if ((testValue > min - 1 && testValue < min) || 
          (testValue > max && testValue < max + 1)) {
        return 'alarm';
      }

      // 超出範圍: < min-1 或 > max+1
      return false;

    } catch (error) {
      return null;
    }
  })()
}}

