    return true;
  }

  // 提取所有欄位值(去除 | 和空格)
  const cells = line.split('|')
    .map(cell => cell.trim())
    .filter(cell => cell !== ''); // 移除空字串

  // 檢查是否所有欄位都是 null
  const allNull = cells.every(cell => cell === 'null');

  // 只有當整列都是 null 時才過濾掉(返回 false)
  return !allNull;
});

// 重新組合過濾後的表格
let processedTable = filteredLines.join('\n');

// 執行替換 - 處理有無空格的情況
