  .replace(/\|\s*true\s*\|/g, '| 🟢 |')     // true 可能有或沒有空格
  .replace(/\|\s*alarm\s*\|/g, '| 🟡 |')    // alarm 警告狀態
  .replace(/\|\s*false\s*\|/g, '| 🔴 |');   // false 可能有或沒有空格

// 返回處理後的結果
return [
