// 取得所有輸入資料
const items = $input.all();

// 1. 分組
const groupedItems = {};
items.forEach(item => {
  const json = item.json;
  const key = `${json.line}_${json.pn}`;
  if (!groupedItems[key]) groupedItems[key] = [];
  groupedItems[key].push(json);
});

const resultData = [];

// === 輔助函式 ===
function isAbnormal(judgeValue) {
  if (!judgeValue) return false;
  const val = String(judgeValue).toLowerCase();
  return val === 'false' || val === 'alarm';
}

function getCenterLine(offsetMeanStr) {
  if (!offsetMeanStr) return 0;
  const str = String(offsetMeanStr).trim();
  if (str.includes('~')) {
    const parts = str.split('~');
    const low = parseFloat(parts[0]);
    const high = parseFloat(parts[1]);
    return (isNaN(low) || isNaN(high)) ? 0 : (low + high) / 2;
  } else {
    const val = parseFloat(str);
    return isNaN(val) ? 0 : val;
  }
}

// === 主邏輯 ===
for (const key in groupedItems) {
  let group = groupedItems[key];

  // 排序：時間由新到舊
  group.sort((a, b) => new Date(b.time) - new Date(a.time));

  const latestItem = group[0];

  // 初始化欄位
  latestItem.need_offset = false; 
  latestItem.need_manual_check = false; // 新增：是否需要人為確認
  latestItem.offset_reason = "Normal"; 
  latestItem.avg_delta = null;

  // 基礎檢查：最新一筆是否異常且總筆數至少有3筆
  if (isAbnormal(latestItem.Judge)) {

    if (group.length >= 3) {
      // 先取前 3 筆進行初步趨勢判斷
      const window3 = group.slice(0, 3);
      const all3Abnormal = window3.every(item => isAbnormal(item.Judge));

      if (all3Abnormal) {
        // 計算這 3 筆的 Delta
        const deltas3 = window3.map(item => {
          const val = parseFloat(item.ppm_avg || 0);
          const center = getCenterLine(item.offset_mean);
          return val - center;
        });

        const all3Positive = deltas3.every(d => d > 0);
        const all3Negative = deltas3.every(d => d < 0);

        // === 分支邏輯 ===

        if (all3Negative) {
          // 情境 2: 偏負時查看筆數 3 筆
          latestItem.need_offset = true;
          latestItem.offset_reason = "Detected 3 consecutive negative errors (Low Bias)";

          // 計算 3 筆平均
          const sumDelta = deltas3.reduce((acc, curr) => acc + curr, 0);
          const rawAvg = -sumDelta / 3; // 取反向
          latestItem.avg_delta = parseFloat(rawAvg.toFixed(3));

        } else if (all3Positive) {
          // 情境 1: 偏正時需查看筆數 5 筆
          // 檢查是否有足夠的 5 筆資料
          if (group.length >= 5) {
            const window5 = group.slice(0, 5);
            const all5Abnormal = window5.every(item => isAbnormal(item.Judge));

            if (all5Abnormal) {
              // 計算 5 筆 Delta
              const deltas5 = window5.map(item => {
                const val = parseFloat(item.ppm_avg || 0);
                const center = getCenterLine(item.offset_mean);
                return val - center;
              });

              // 再次確認這 5 筆是否真的都是正向 (雖然前3筆是正的，但第4,5筆也要確認)
              const all5Positive = deltas5.every(d => d > 0);

              if (all5Positive) {
                latestItem.need_offset = true;
                latestItem.offset_reason = "Detected 5 consecutive positive errors (High Bias)";

                // 計算 5 筆平均
                const sumDelta = deltas5.reduce((acc, curr) => acc + curr, 0);
                const rawAvg = -sumDelta / 5; // 取反向
                latestItem.avg_delta = parseFloat(rawAvg.toFixed(3));
              } else {
                 latestItem.offset_reason = "Positive bias detected but not consistent over 5 items";
              }
            } else {
               latestItem.offset_reason = "Positive bias detected but historical data (4th/5th) is not abnormal";
            }
          } else {
            latestItem.offset_reason = `Positive bias detected but insufficient data (Need 5, Has ${group.length})`;
          }

        } else {
          // 情境 3: 上下跳動 (非全正也非全負，但都是異常)
          latestItem.need_manual_check = true; // 發出警告
          latestItem.need_offset = false;      // 不自動調整
          latestItem.offset_reason = "Oscillation detected (Mixed positive/negative errors)";

          // 這裡不計算 avg_delta，或者您可以選擇計算但不做 offset
          latestItem.calc_details = { deltas: deltas3 };
        }

      } else {
        latestItem.offset_reason = "Latest 3 items are not all abnormal";
      }
    } else {
      latestItem.offset_reason = "Insufficient historical data (< 3)";
    }
  }

  resultData.push({ json: latestItem });
}

return resultData;

