    // 狀況：匹配到最後一筆 -> 僅蒐集最後一筆
    selectedItems = [group[matchIndex]];
  } else {
    // 狀況：找到匹配 -> 蒐集匹配之後的所有工單
    selectedItems = group.slice(matchIndex + 1);
  }

  // 3. 將篩選出的資料放入最終結果陣列
  selectedItems.forEach(item => {
    finalResults.push({ json: item });
  });
});

