    return []; // 如果沒有符合條件的項目，就停止後續流程
}

// 2. 提取 mclot 並加上單引號，組合成字串
const lotList = changedLots.map(item => `'${item.json.mclot}'`).join(',');

// 3. 輸出給下一個節點使用
return [{ json: { lotList: lotList } }];

return items.map(item => {
    const data = item.json;

    // 判斷：只有當標記為 Y，且確實有從第二張表對接到數據時才處理
    if (data.is_lot_changed === 'Y' && data.table2_final_output !== undefined) {

        // 取得原始數值 (表 1)
        const originalOutput = parseFloat(data.output || 0);
        const originalDelta = parseFloat(data.delta || 0);

        // 取得結案數值 (表 2)
        const finalOutputValue = parseFloat(data.table2_final_output);

        // 計算邏輯：
        // 1. 找出這筆工單在該時段開始前的「起始累計值」 (Baseline)
        const baseline = originalOutput - originalDelta;

        // 2. 更新當前的 output 為表 2 的最新值
        data.output = finalOutputValue;

        // 3. 根據表 2 的值重新計算這一筆的正確 delta
        data.delta = (finalOutputValue - baseline).toFixed(0);

        data.data_status = "Finalized from Table 2";
    } else {
        // 如果是 N，或者表 2 沒有對應資料，則完全保留原始表 1 的數據
        data.data_status = "Original Step Data";
    }

    // 刪除輔助用的欄位，讓輸出乾淨
    delete data.table2_final_output;
    delete data.lotdate;


    return { json: data };
});

