// 1. 直接從輸入抓取「主資料」 (13 筆)
const mainItems = $input.all();

// 2. 抓取「機線表」資料 (對照資料)
const sqlItems = $('機線表').all();

console.log('主資料筆數:', mainItems.length);
console.log('機線表筆數:', sqlItems.length);

// 3. 建立對照 Map (以 mes_txcid 為 Key)
const equipmentMap = {};
sqlItems.forEach(item => {
  const data = item.json;
  // 取得 mes_txcid 作為比對基準 (轉大寫並去空白，增加比對成功率)
  const mesTxcid = data.mes_txcid ? String(data.mes_txcid).toUpperCase().trim() : null;

  if (mesTxcid) {
    equipmentMap[mesTxcid] = {
      lineid: data.lineid || "",
      location: data.location || ""
    };
  }
});

// 4. 比對並填充主表資料
const result = mainItems.map(item => {
  // 為了不更動原始物件，建議展開處理 (或直接修改 row)
  const row = { ...item.json };

  // 取得主資料的 eqp_id (例如 FT_1534)
  const searchId = row.eqp_id ? String(row.eqp_id).toUpperCase().trim() : '';

  // 進行 Lookup
  if (equipmentMap.hasOwnProperty(searchId)) {
    const match = equipmentMap[searchId];
    row['線別'] = match.lineid;   // 取得 lineid 填回「線別」
    row['樓層'] = match.location; // 取得 location 填回「樓層」
  } else {
    // 若找不到對應，保留原值或標記
    row['線別'] = row['線別'] || "Not Found";
    row['樓層'] = row['樓層'] || "Not Found";
  }

  return { json: row };
});

return result;

// 1. 取得來源 1 (由前方的 Merge 或 Filter 傳入的當前資料)
const source1 = $input.all(); 

// 2. 直接跨過 Merge 節點，去抓來源 2 的完整資料
// 請將下方的 '來源2節點名稱' 改成您畫面上來源 2 那個 Node 的名稱

const source2 = $('機線表').all(); 

// 3. 建立 lookupMap (查找表)
const faLookup = {};

for (const item of source2) {
  const data = item.json;

  // 取得 lineid 並強制轉字串 + 去空白 (確保 SPX-28 能對上)
  const lid = data.lineid ? String(data.lineid).trim() : null;
  const mesid = data.mes_txcid ? String(data.mes_txcid).trim() : "";

  // 判斷條件：只要 lineid 存在，且 mes_txcid 是 FA 開頭
  if (lid && mesid.startsWith("FA")) {
    faLookup[lid] = mesid;
  }
}

// 4. 進行查找合併
return source1.map(item => {
  // 取得來源 1 的「線別」並去空白
  const lineName = item.json["線別"] ? String(item.json["線別"]).trim() : null;

  // 查找 Map，若有對應則填入，否則填 null
  item.json["FA_txcid"] = (lineName && faLookup[lineName]) ? faLookup[lineName] : null;

  return item;
});

const token = $('get token').first().json.data.access_token;
const results = [];

for (const item of $input.all()) {
  const partNumber = item.json['料號'];
  const faTxcid = item.json['eqp_id'];

  // 如果料號本身就是無效值，直接給 null 並跳過 API 調用
  if (!partNumber || partNumber === 'null' || partNumber === null) {
    item.json.process_time = null; // 修改：原本是 0，改為 null
    results.push(item);
    continue;
  }

  const options = {
    method: 'POST',
    url: `http://192.168.37.33:32198/api/data/detail/open/2055087873280786433`,
    qs: {
      page: 1,
      limit: 100,
      arg_wo_type: 'P',
      arg_step_id: 'FT',
      arg_part_number: partNumber,
      arg_eqp_id: faTxcid
    },
    headers: {
      'Authorization': `Bearer ${token}`,
      'Content-Type': 'application/json'
    },
    json: true 
  };

  try {
    const response = await helpers.httpRequest(options);

    // 檢查資料層級：response -> data -> data (array) -> [0] -> process_time
    // 使用 Optional Chaining 確保安全提取
    const processTime = response.data?.data?.[0]?.process_time;

    // 修改邏輯：
    // 如果 processTime 是 undefined (陣列為空或沒這欄位)，則填入 null
    item.json.process_time = (processTime !== undefined) ? processTime : null;

  } catch (error) {
    // API 調用失敗（如網路超時、401等）也填入 null
    item.json.process_time = null;
    item.json.debug_error = error.message;
  }

  results.push(item);
}

return results;

// Code Node
const shift = $json.output.shift;
const starttime = $json.output.starttime;
// 假設 endtime 存在，若沒有則使用 starttime 作為預設值
const endtime = $json.output.endtime || starttime; 
const locationString = $json.output.location; // 取得 location 原始字串

let timeCondition = "";
let locationCondition = "";
let lineidCondition = ""; 


// --- 處理 location 邏輯 (支援多樓層逗號分隔) ---

// 1. 處理 location 字串：
//    split(',') 根據逗號分割
//    map(s => s.trim()) 移除分割後每個項目的前後空白 (避免 ' A-4F' 這種情況)
//    filter(Boolean) 移除空字串 (避免 input 是 "A-3F,,A-4F" 造成錯誤)
const locations = locationString ? locationString.split(',').map(s => s.trim()).filter(Boolean) : [];

// 2. 根據 locations 陣列生成 SQL 條件
if (locations.length > 0) {
    // 將每個 location 值轉換為 "B.location = 'A-2F'" 格式
    const locationClauses = locations.map(loc => {
        return `B.location = '${loc}'`;
    });

    // 用 ' OR ' 將所有條件串接起來，並加上括號
    locationCondition = `AND (${locationClauses.join(' OR ')})`;
}

// --- 處理時間區間邏輯 (維持原樣) ---

// 判斷 shift 是否為空值 (包含 undefined, null, "")
if (!shift) {
  // 當 shift 為空時：Start Time 08:00 ~ End Time +1 Day 08:00
  timeCondition = `AND pmstartdate >= TO_TIMESTAMP('${starttime} 08:00:00', 'YYYY/MM/DD HH24:MI:SS') AND pmstartdate <= (DATE '${endtime}' + INTERVAL '1 day' + TIME '08:00:00')`;

} else if (shift === 'day') {
  // 日班：當天 08:00 ~ 當天 20:00
  timeCondition = `AND pmstartdate >= TO_TIMESTAMP('${starttime} 00:00:00', 'YYYY/MM/DD HH24:MI:SS') AND pmstartdate <= TO_TIMESTAMP('${starttime} 23:00:00', 'YYYY/MM/DD HH24:MI:SS')`;

} else if (shift === 'night') {
  // 夜班：當天 20:00 ~ 隔天 08:00
  timeCondition = `AND pmstartdate >= TO_TIMESTAMP('${starttime} 16:00:00', 'YYYY/MM/DD HH24:MI:SS') AND pmstartdate <= (DATE '${starttime}' + INTERVAL '1 day' + TIME '12:00:00')`;
}

return [{
  json: {
    ...$json, // 保留原始所有資料
    timeCondition: timeCondition,
    locationCondition: locationCondition,
    lineidCondition: lineidCondition
  }
}];

// 1. 取得 Input Node 1 的所有資料
const items1 = $input.all();

// 2. 取得 Input Node 2 的所有資料 (請根據你實際的節點名稱修改，例如 'MySQL' 或 'Execute Workflow')
// 假設你的 Input Node 2 節點名稱叫做 "Input Node 2"
const items2 = $( 'B1停機' ).all();

// 3. 將 Input Node 2 的資料建立成 Map，方便快速比對
// 這樣做效率最高，時間複雜度是 O(N)
const node2Map = {};
items2.forEach(item => {
  const data = item.json;
  if (data.txcid) {
    // 將 txcid 轉為字串，並使用 padStart(4, '0') 確保不足4位數時前面補0
    const formattedTxcid = String(data.txcid).trim().padStart(4, '0');
    node2Map[formattedTxcid] = data.pmstartdate;
  }
});

// 4. 開始比對並合併資料到 Input Node 1
const result = items1.map(item => {
  // 複製原始資料，避免改動到唯讀屬性
  const newJson = { ...item.json };
  const faTxcid = newJson.FA_txcid;

  let matchedPmStartDate = null;

  if (faTxcid) {
    // 使用正規表達式提取字串中的所有數字 (例如 "FA_0758" -> "0758")
    const match = faTxcid.match(/\d+/);
    if (match) {
      const extractedId = match[0]; // 提取出來的數字字串

      // 去比對剛才建立好的 Map
      if (node2Map[extractedId]) {
        matchedPmStartDate = node2Map[extractedId];
      }
    }
  }

  // 新增欄位在 input node1 上，沒比對到自然就是 null
  newJson.pmstartdate = matchedPmStartDate;

  return { json: newJson };
});

return result;

