  (() => {
    const targetStr = $('If11').item.json.output.shift === 'day' ? '20:00:00' : '08:00:00';
    const userStr = $('If11').item.json.output.time || '00:00:00';

    const pmEndTimeStr = $json.pmendtime; 

    const toSec = (timeStr) => {
      if (!timeStr) return 0;
      const [h, m, s] = timeStr.split(':').map(Number);
      return (h * 3600) + (m * 60) + (s || 0);
    };

    const targetSec = toSec(targetStr);
    let currentUserSec = toSec(userStr); 

    if (pmEndTimeStr) {
      const pmEndTimeSec = toSec(pmEndTimeStr);


      if (currentUserSec < pmEndTimeSec) {
        currentUserSec = pmEndTimeSec;
      }
    }


    let diffInSeconds = targetSec - currentUserSec;
    if (diffInSeconds < 0) {
      diffInSeconds += 86400; 
    }

    return Math.round(diffInSeconds);
  })()
}}

